\displaystyle{\begin{aligned}[t]
    \frac{7}{10} \div \left(-\frac{4}{25}\right)
        \amp = \frac{7}{10} \cdot \left(-\frac{25}{4}\right) \amp \hbox{We can divide the first denominator and the second numerator by 5.}\\
        \amp = \frac{7}{2 }\cdot\left(-\frac{5}{4}\right) \\
        \amp = -\frac{35}{8}
\end{aligned}
    }
